import React from "react"
import { Link } from "gatsby-plugin-intl"

export default function IntlLink({ to, language, children, onClick, ...rest }) {

	if (to === "#") {
		return <a href="#" {...rest}>{children}</a>
	}
	else if (!to || to === "") {
		return children
	}

	return (
		<Link {...rest} to={to} language={language}>
			{children}
		</Link>
	)
}