
import { useStaticQuery, graphql } from "gatsby"

export default function useAdvisorsQuery(lang) {

  const tmp = useStaticQuery(graphql`
    query {
      allMdx(
        filter: {
          fields: {
            collection: {eq: "members"},
          },
          frontmatter: {
            job_title_value: {gt: 9.9}
          }
        },
        sort: {fields: [frontmatter___job_title_value, frontmatter___title], order: [DESC, ASC]}
      ) {
        nodes {
          frontmatter {
            memberid
            title
            job_title
            image {
              publicURL
              childImageSharp {
                gatsbyImageData(layout: CONSTRAINED)
              }
            }
          }
          fields {
            slug
            lang
          }
        }
      }
    }
  `)

  return tmp.allMdx.nodes.filter(m => m.fields.lang === lang)
  
}