export function formatDate(date, lang="th") {
  if (lang === "en")
    lang = "en-GB"
  return new Date(date).toLocaleDateString(lang, {day: 'numeric', month: 'long', year: 'numeric'})
}

// takes in the entire frontmatter
export function formatFrontmatterDate(f, lang="th") {
  
  let data = new Date(f.date)
  let date_end = new Date(f.date_end)
  let updated = new Date(f.updated)

  let str = formatDate(data, lang)
  if (updated && data.valueOf() < updated.valueOf()) {
    str += ` (${lang === "th" ? "ปรับปรุงล่าสุด" : "Updated"} ${formatDate(updated, lang)})`
  }
  else if (date_end && data.valueOf() < date_end.valueOf()) {
    if (data.getMonth() === date_end.getMonth() && data.getFullYear() === date_end.getFullYear()) {
      str = `${new Date(data).toLocaleDateString(lang, {day: 'numeric'})}–${formatDate(date_end, lang)}`
    }
    else if (data.getFullYear() === date_end.getFullYear()) {
      str = `${new Date(data).toLocaleDateString(lang, {day: 'numeric', month: 'long'})} – ${formatDate(date_end, lang)}`
    }
    else {
      str = `${formatDate(data, lang)} – ${formatDate(date_end, lang)}`
    }
  }
  return str
}

export function dateOffset(start, offset=1) {
  return dayjs(start).add(offset, 'day').$d
}

export function timeFromNum(num) {
  return dayjs(new Date(0, 0, 0, 0, num)).format('HH:mm')
}

export function getAuthors(aList, qResults, lang) {
  if (aList.length === 0)
    return []
	qResults = qResults.filter(result => result.fields.lang === lang)
	const qOrder = qResults.map(result => result.frontmatter.memberid)
	return aList.map(author => {
    if (qOrder.includes(author))
      return qResults[qOrder.indexOf(author)]
    return author
  })
}

export function FormattedAuthor({ author, suffix="" }) {
  return(
    <Link to={!author.frontmatter?.exclude && author.fields?.originalPath}>
      {`${author.frontmatter?.title || author}${suffix}`}
    </Link>
  )
}

