// https://medium.com/@chrisfitkin/how-to-get-query-string-parameter-values-in-gatsby-f714161104f
const parseOptions = {
  arrayFormat: 'separator',
  arrayFormatSeparator: '|'
}
export const withLocation = ComponentToWrap => props => (
  <Location>
    {({ location, navigate }) => (
      <ComponentToWrap
        {...props}
        location={location}
        navigate={navigate}
        params={location.search ? queryString.parse(location.search, parseOptions) : {}}
        parseOptions={parseOptions}
      />
    )}
  </Location>
)

