import React from "react"
import Link from "../IntlLink"
import { getString } from "../../util"
import { GatsbyImage } from "gatsby-plugin-image"
import { useStaticQuery, graphql } from "gatsby"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function Author({ author, link, flexible, typesenseField, showOrg=true, showJobTitle=false, hoverEffect=false, lang, name, indexThis=true, placeCenter=false }) {
	const cx = classNames.bind(styles);
	const placeholderPic = useStaticQuery(graphql`
		{
			allFile(
				filter: {sourceInstanceName: {eq: "images"}, relativeDirectory: {eq: "placeholder"}, name: {eq: "user"}}
			) {
				nodes {
					childImageSharp {
						gatsbyImageData(layout: CONSTRAINED, width: 200, height: 200)
					}
				}
			}
		}
	`)

	// only name is provided
	if (!author && name) {
		return(
			<div className={cx("card", {"flexible": flexible})}>
				<GatsbyImage image={placeholderPic.allFile.nodes[0].childImageSharp.gatsbyImageData} alt={name} className={cx("pic", {hoverimg: hoverEffect})} />
				<div className={cx("details")}>
					<div className={cx("name")} {...(indexThis && {'data-typesense-field': typesenseField})}>{name}</div>
				</div>
			</div>
		)
	}

	return(
		<Link to={!author.exclude && link} className={cx("nolinkcolor", "nohover")}>
			<div className={cx("card", {"flexible": flexible, "center": placeCenter})}>
				<GatsbyImage image={author.image ? author.image.childImageSharp.gatsbyImageData : placeholderPic.allFile.nodes[0].childImageSharp.gatsbyImageData} alt={author.title || getString(author.name)} className={cx("pic", {hoverimg: hoverEffect})} />
				<div className={cx("details")}>
					<div className={cx("name")} {...(indexThis && {'data-typesense-field': typesenseField})}>{author.title || getString(author.name, lang)}</div>
					{showOrg && author.org && <div className={cx("org")}>{getString(author.org.id || author.org, lang)}</div>}
					{showJobTitle && <div className={cx("org")}>{author.job_title}</div>}
				</div>
			</div>
		</Link>
	)
}