import { useStaticQuery, graphql } from "gatsby"

export default function usePRNOfficersQuery(lang) {

  const tmp = useStaticQuery(graphql`
    query {
      allMdx(
        filter: {
          fields: {
            collection: {eq: "members"},
          },
          frontmatter: {
            prn_officer: {eq: true}
          }
        },
        sort: {fields: frontmatter___title}
      ) {
        nodes {
          frontmatter {
            memberid
            title
            org
            email
            image {
              publicURL
              childImageSharp {
                gatsbyImageData(layout: CONSTRAINED, width: 200, height: 200)
              }
            }
          }
          fields {
            slug
            lang
          }
        }
      }
    }
  `)

  return tmp.allMdx.nodes.filter(m => m.fields.lang === lang)
  
}