import { useStaticQuery, graphql } from "gatsby"

export default function usePastFellowsQuery(lang) {

  const tmp = useStaticQuery(graphql`
    query {
      allMdx(
        filter: {
          fields: {
            collection: {eq: "members"},
          },
          frontmatter: {
            current_fellow: {ne: true},
            first_visit: {gt: 0}
          }
        },
        sort: {
          fields: [frontmatter___first_visit, frontmatter___title],
          order: [DESC, ASC]
        }
      ) {
        nodes {
          frontmatter {
            memberid
            title
            org
            email
            image {
              publicURL
              childImageSharp {
                gatsbyImageData(layout: CONSTRAINED, width: 200, height: 200)
              }
            }
          }
          fields {
            slug
            lang
          }
        }
      }
    }
  `)

  return tmp.allMdx.nodes.filter(m => m.fields.lang === lang)
  
}