function processColors(obj, colors) {
	if (obj == null)
		return
	for (const [k, v] of Object.entries(obj)) {
		if (v == null)
			continue
		if (typeof v === "object") {
			obj[k] = processColors(v, colors)
		}
		else if (v[0] === '$') { // styles
			obj[k] = styles[v.substring(1)]
		}
		else if (v[0] === '@') { //colors
			if (v.substring(v.length - 3, v.length - 2) === '@')
				obj[k] = colors[v.substring(1, v.length - 3)] + v.substring(v.length - 2)
			else
				obj[k] = colors[v.substring(1)]
		}
	}
	return obj
}

