import React from "react"
import { Helmet } from "react-helmet"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"
import globalStyles from '../../styles/_variables.module.scss'

export default function PIERLogo() {

	const cx = classNames.bind(styles);

	let toPaper = () => {}
	let toP = () => {}

	let tl = null

	React.useEffect(() => {
		toPaper = () => {
			if (tl)
				tl.pause()
			const x = window.anime.get(document.querySelector(`#thelogo .${cx("plus")}`), 'rotateZ', 'deg')
			const plusRotate = parseInt(x.substring(0, x.length - 3))
			tl = window.anime.timeline({autoplay: false})
			tl.add({
				targets: `#thelogo .${cx("plus")}`,
				scale: 0,
				rotateZ: 90 * (Math.floor(plusRotate / 90) + 1),
				duration: 500,
				easing: "easeInSine",
			}, 0)
			tl.add({
				targets: `#thelogo .${cx("p")}`,
				d: {value: "M96.9,44.7c0.1-5.6,0-44.7,0-44.7H0v137.6c20,0,49.7,0,96.9,0c0,0,0,-10,0,-36.3z"},
				duration: 500,
				easing: "easeOutCubic",
			}, 200)
			tl.add({
				targets: `#thelogo .${cx("p")}`,
				fill: "#f5e8cb",
				duration: 500,
				easing: "easeOutCubic",
			}, 400)
			tl.add({
				targets: `#thelogo .${cx("lines")}`,
				scaleX: [0, 1],
				delay: window.anime.stagger(50, {start: 400}),
				duration: 400,
			}, 0)
			tl.play()
		}
		toP = () => {
			if (tl)
				tl.pause()
			const x = window.anime.get(document.querySelector(`#thelogo .${cx("plus")}`), 'rotateZ', 'deg')
			const plusRotate = parseInt(x.substring(0, x.length - 3))
			tl = window.anime.timeline({autoplay: false})
			tl.add({
				targets: `#thelogo .${cx("plus")}`,
				scale: 1,
				rotateZ: 90 * (Math.floor(plusRotate / 90) + 1),
				duration: 800,
				easing: "easeOutCubic",
			}, 400)
			tl.add({
				targets: `#thelogo .${cx("p")}`,
				d: {value: "M96.9,44.7c0.1-5.6,0-44.7,0-44.7H0v137.6c0,0,49.7,2.6,49.5-56.6c16.1,3.5,47.3,0.1,47.3,-36.3z"},
				duration: 800,
				easing: "easeOutBack",
			}, 200)
			tl.add({
				targets: `#thelogo .${cx("p")}`,
				fill: globalStyles.primaryColor,
				duration: 800,
				easing: "easeOutCubic",
			}, 200)
			tl.add({
				targets: `#thelogo .${cx("lines")}`,
				scaleX: 0,
				duration: 400,
				easing: "easeOutCubic",
			}, 0)
			tl.play()
		}
	})

	return(
		<React.Fragment>
			<Helmet>
				<script src="https://cdnjs.cloudflare.com/ajax/libs/animejs/3.2.1/anime.min.js" />
			</Helmet>
			<svg id="thelogo"
					version="1.1" x="0px" y="0px" viewBox="0 0 96.9 170"
					onMouseEnter={() => toPaper()} onMouseLeave={() => toP()}
				>
				<g>
					{/*<polygon className="pier-logo--plus" points="80.2,118.1 80.2,100 77.4,100 77.4,118.1 59.3,118.1 59.3,121 77.4,121 77.4,137.6 80.2,137.6 80.2,121 96.9,121 96.9,118.1"/>*/}
					<g className={cx("plus")}>
						<path d="M78.1,100 v37.6" strokeWidth="2.8"/>
						<path d="M59.3,118.8 h37.6" strokeWidth="2.8"/>
					</g>
					<path className={cx("p")} d="M96.9,44.7c0.1-5.6,0-44.7,0-44.7H0v137.6c0,0,49.7,2.6,49.5-56.6c16.1,3.5,47.3,0.1,47.3,-36.3z"/>		
					{/* original logo path => <path className="pier-logo--p" d="M96.9,44.7c0-10.4,0-44.7,0-44.7H0v137.6c0,0,49.5,2.9,49.5-56.6c0,0,13.5,2.8,25.5-1.2C87.4,75.6,96.9,62.9,96.9,44.7z"/>*/}
					{
						[...Array(7).keys()].map(i =>
							<path key={i} className={cx("lines")} d={`M10,${15+i*10} H86.8 v3 H10 z`}/>
						)
					}
					<g className={cx("text")}>
						<polygon points="30.3,169.9 33.7,169.9 33.7,147.2 30.3,149.8"/>
						<polygon points="63.8,151.6 65.7,148.6 50.2,148.6 50.2,169.9 65,169.9 65,167 53.6,167 53.6,160.7 62.7,160.7 
							62.7,157.7 53.6,157.7 53.6,151.6"/>
						<path d="M88.6,161.5c4-0.4,6.6-2.9,6.6-6.5c0-3.9-3.1-6.5-7.6-6.5h-9v21.4H82v-18.4h5.4c1.3,0,4.4,0.3,4.4,3.5
							c0,3.2-3.1,3.5-4.4,3.5h-1.3l-2.4,2.5l8.6,8.9h4.5L88.6,161.5z"/>
						<path d="M9,148.6H0v21.4h3.4v-8.4v-10h5.4c1.3,0,4.4,0.3,4.4,3.5c0,3.2-3,3.5-4.4,3.5H5.9l-2.2,3H9
							c4.5,0,7.6-2.6,7.6-6.5C16.6,151.2,13.6,148.6,9,148.6z"/>
					</g>
				</g>
			</svg>
		</React.Fragment>
	)
}