import React from "react"
import loadable from '@loadable/component'

let AuthorsGraph = null
AuthorsGraph = typeof window === "undefined"
	? null
	: loadable(() => import('./component'))
export default function LazyAuthorsGraph({ lang }) {
  return (
    AuthorsGraph && <AuthorsGraph lang={lang} />
  )
}